const wb_captured_symbol_variant *wb_get_captured_symbol_variant(int symbol_id, int variant_seed)
{
	int n_symbols = (int)(sizeof(captured_symbol_table) / sizeof(captured_symbol_table[0]));
	for (int i = 0; i < n_symbols; i++)
	{
		if (captured_symbol_table[i].symbol_id != symbol_id || captured_symbol_table[i].n_variants <= 0)
			continue;
		uint32_t pick = (uint32_t)variant_seed;
		pick ^= pick >> 16;
		pick *= 0x7feb352dU;
		pick ^= pick >> 15;
		pick *= 0x846ca68bU;
		pick ^= pick >> 16;
		return captured_symbol_table[i].variants[pick % captured_symbol_table[i].n_variants];
	}
	return NULL;
}

wb_plane_figure *wb_get_captured_symbol_figure(int symbol_id, int variant_seed)
{
	const wb_captured_symbol_variant *variant = wb_get_captured_symbol_variant(symbol_id, variant_seed);
	return variant ? variant->figure : NULL;
}
